function showChipDesc(code, desc, ev) {
  // tooltip mantido para compatibilidade mas não usado mais
}
function hideChipDesc() {}

function openChipModal(code) {
  var ind = CONSULT_MAP[code];
  if (!ind) return;
  var desc = (DESC_NOTAS[code] || "Descrição não cadastrada");
  var fecList = CHIP_FECH_MAP[code] || [];

  var overlay = document.getElementById("chip-modal-overlay");
  var ic = document.getElementById("chip-modal-ic");
  var codeEl = document.getElementById("chip-modal-code");
  var fullnameEl = document.getElementById("chip-modal-fullname");
  var badgeEl = document.getElementById("chip-modal-badge");
  var bodyEl = document.getElementById("chip-modal-body");

  ic.style.background = ind.bg;
  ic.style.border = "2px solid " + ind.border;
  ic.style.color = ind.color;
  ic.textContent = code.charAt(0);

  codeEl.textContent = code;
  codeEl.style.color = ind.color;
  fullnameEl.textContent = desc;

  badgeEl.textContent = ind.label + " · " + ind.desc;
  badgeEl.style.color = ind.color;
  badgeEl.style.background = ind.bg;
  badgeEl.style.borderColor = ind.border;

  if (fecList.length === 0) {
    bodyEl.innerHTML = '<div class="chip-modal-empty">Nenhum código de fechamento mapeado para este serviço.</div>';
  } else {
    var rows = fecList.map(function(f) {
      return '<div class="chip-modal-cod-row">' +
        '<span class="chip-modal-cod-num">' + f.cod + '</span>' +
        '<span class="chip-modal-cod-desc">' + f.desc + '</span>' +
        '</div>';
    }).join('');
    bodyEl.innerHTML = '<div class="chip-modal-section-title">Códigos de Fechamento Aceitos (' + fecList.length + ')</div>' + rows;
  }

  overlay.classList.add("visible");
  document.body.style.overflow = "hidden";
}

function hideChipModal() {
  document.getElementById("chip-modal-overlay").classList.remove("visible");
  document.body.style.overflow = "";
}

function closeChipModal(e) {
  if (e.target === document.getElementById("chip-modal-overlay")) hideChipModal();
}

// ESC fecha modal
document.addEventListener("keydown", function(e) {
  if (e.key === "Escape") hideChipModal();
});

function consultRender() {
  var grid = document.getElementById("consult-grid");
  grid.innerHTML = INDICADORES.map(function (ind) {
    var chips = ind.servicos.map(function (s) {
      var desc = DESC_NOTAS[s] || s;
      return "<span class=\"consult-chip\" style=\"color:" + ind.color + ";background:" + ind.bg + ";border-color:" + ind.border + "\" onclick=\"openChipModal('" + s + "')\" title=\"" + desc + "\">" + s + "</span>";
    }).join("");
    return "<div class=\"consult-card c-" + ind.id + "\">" +
      "<div class=\"consult-header\">" +
      "<div class=\"consult-header-ic\" style=\"background:" + ind.bg + ";border:1.5px solid " + ind.border + ";color:" + ind.color + "\">" + ind.label.charAt(0) + "</div>" +
      "<div class=\"consult-header-title\" style=\"color:" + ind.color + "\">" + ind.label + "</div>" +
      "<span class=\"consult-header-count\" style=\"color:" + ind.color + ";background:" + ind.bg + ";border-color:" + ind.border + "\">" + ind.servicos.length + "</span>" +
      "</div>" +
      "<div class=\"consult-chips\">" + chips + "</div>" +
      "</div>";
  }).join("");
}

function consultLimpar() {
  document.getElementById("consult-search").value = "";
  consultSearch();
}

/* ── Tab switcher ── */
function consultSwitchTab(tab) {
  ["servicos","locais"].forEach(function(t) {
    document.getElementById("consult-pane-" + t).classList.toggle("pane-active", t === tab);
    document.getElementById("tab-btn-" + t).classList.toggle("active", t === tab);
  });
  // Lazy render locais on first switch
  if (tab === "locais") {
    var grid = document.getElementById("locais-grid");
    if (grid && !grid.dataset.rendered) locaisRender();
  }
}


